-- =====================  COUNTRY TRIP INFO  =====================
-- Fills in best_time_to_visit / travel_summary / common_tips / common_scams /
-- visa_notes only where they are currently empty. Curated rows stay untouched.
with data(code, best_time, summary, tips, scams, visa) as (
  values
  ('AT', 'May–Sep, Dec ski season', 'Vienna and the Alps — orderly, safe, and clean.', ARRAY['Pickpockets target tourists in big cities — keep bags zipped', 'Validate train tickets before boarding', 'Tipping is optional, rounding up is appreciated']::text[], ARRAY['Petition / ring-drop scams near major monuments', 'Friendship-bracelet street performers', 'Taxi meter "broken" trick — use Uber/Bolt']::text[], 'Schengen Area — 90 days visa-free for many passports.'),
  ('BE', 'Apr–Sep', 'Brussels, Bruges, beer and chocolate. Watch big-city pickpockets.', ARRAY['Pickpockets target tourists in big cities — keep bags zipped', 'Validate train tickets before boarding', 'Tipping is optional, rounding up is appreciated']::text[], ARRAY['Petition / ring-drop scams near major monuments', 'Friendship-bracelet street performers', 'Taxi meter "broken" trick — use Uber/Bolt']::text[], 'Schengen Area — 90 days visa-free for many passports.'),
  ('CH', 'Jun–Sep, Dec–Feb skiing', 'Among the safest in the world. Trains run on time, prices high.', ARRAY['Pickpockets target tourists in big cities — keep bags zipped', 'Validate train tickets before boarding', 'Tipping is optional, rounding up is appreciated']::text[], ARRAY['Currency-exchange short-changing', 'Inflated taxi fares — use Uber/Bolt']::text[], 'Schengen — 90 days visa-free for many passports.'),
  ('DE', 'May–Sep, Dec markets', 'Reliable and well-organized. Pickpockets in major train hubs.', ARRAY['Pickpockets target tourists in big cities — keep bags zipped', 'Validate train tickets before boarding', 'Tipping is optional, rounding up is appreciated']::text[], ARRAY['Petition / ring-drop scams near major monuments', 'Friendship-bracelet street performers', 'Taxi meter "broken" trick — use Uber/Bolt']::text[], 'Schengen Area — 90 days visa-free for many passports.'),
