update public.countries c set
  best_time_to_visit = coalesce(nullif(c.best_time_to_visit, ''), data.best_time),
  travel_summary     = coalesce(nullif(c.travel_summary, ''),     data.summary),
  common_tips        = case when coalesce(array_length(c.common_tips, 1), 0) = 0  then data.tips  else c.common_tips  end,
  common_scams       = case when coalesce(array_length(c.common_scams, 1), 0) = 0 then data.scams else c.common_scams end,
  visa_notes         = coalesce(nullif(c.visa_notes, ''),         data.visa)
from data
where c.code = data.code;
